fn solve(n: i64) -> String {
    let n_squared = n * n;
    let hex_str = format!("{:X}", n_squared);

    let n_cubed = n * n * n;
    let base36_digits: Vec<char> = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ".chars().collect();
    let mut base36_str = String::new();
    let mut temp = n_cubed;

    if temp == 0 {
        base36_str.push('0');
    } else {
        while temp > 0 {
            let remainder = (temp % 36) as usize;
            base36_str.insert(0, base36_digits[remainder]);
            temp /= 36;
        }
    }

    hex_str + &base36_str
}
